"use server";

import { supabase } from "@/lib/supabase";
import { User } from "@/lib/services/user-service";

export async function loginAction(email: string, password: string): Promise<{ success: boolean; user?: User; error?: string }> {
    try {
        const { data, error } = await supabase
            .from("users")
            .select("*")
            .eq("email", email)
            .single();

        if (error || !data) {
            return { success: false, error: "Authentication failed: Identity not found in operational records." };
        }

        const user = data as User;
        const dbPassword = user.password || "password123";

        if (dbPassword !== password) {
            return { success: false, error: "Access denied: Secure keyphrase mismatch." };
        }

        return { success: true, user };
    } catch (err: unknown) {
        return { success: false, error: "System failure: Connection to intelligence nexus interrupted." };
    }
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Sparkles, Lock, Mail, ArrowRight, Loader2, AlertCircle } from "lucide-react";
import { loginAction } from "./actions";
import { useAuth } from "@/lib/contexts/auth-context";

export default function LoginPage() {
    const { login } = useAuth();
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const router = useRouter();

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        setError(null);

        try {
            const result = await loginAction(email, password);
            if (result.success && result.user) {
                login(result.user);
                router.push("/");
            } else {
                setError(result.error || "Authentication failed.");
                setIsLoading(false);
            }
        } catch (err) {
            setError("Communication link severed. Retry sequence.");
            setIsLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-zinc-50 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-zinc-100 via-transparent to-transparent">
            <div className="w-full max-w-lg space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-700">
                {/* Branding */}
                <div className="text-center space-y-6">
                    <div className="inline-flex h-24 w-24 items-center justify-center rounded-[32px] bg-blue-600 shadow-2xl shadow-blue-600/40 transition-transform hover:scale-105 duration-500">
                        <Sparkles size={48} className="text-white" />
                    </div>
                    <div className="space-y-1">
                        <h1 className="text-5xl font-black tracking-tighter text-zinc-900">CRM Core</h1>
                        <p className="text-sm font-bold uppercase tracking-[0.3em] text-zinc-400 opacity-60">Operational Command Center</p>
                    </div>
                </div>

                {/* Login Card */}
                <div className="bg-white/70 backdrop-blur-3xl p-10 rounded-[48px] border border-white shadow-2xl shadow-zinc-200/50">
                    <form onSubmit={handleLogin} className="space-y-6">
                        <div className="space-y-2">
                            <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-400 ml-2">Email</label>
                            <div className="relative group">
                                <Mail className="absolute left-6 top-1/2 -translate-y-1/2 text-zinc-400 group-focus-within:text-zinc-900 transition-colors" size={20} />
                                <input
                                    required
                                    type="email"
                                    placeholder="admin@crm.com"
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                    className="w-full rounded-3xl border border-zinc-100 bg-zinc-50/50 px-14 py-5 text-base font-bold transition-all focus:bg-white focus:border-blue-600 focus:outline-none focus:ring-4 focus:ring-blue-600/5"
                                />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-400 ml-2">Password</label>
                            <div className="relative group">
                                <Lock className="absolute left-6 top-1/2 -translate-y-1/2 text-zinc-400 group-focus-within:text-zinc-900 transition-colors" size={20} />
                                <input
                                    required
                                    type="password"
                                    placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    className="w-full rounded-3xl border border-zinc-100 bg-zinc-50/50 px-14 py-5 text-base font-bold transition-all focus:bg-white focus:border-blue-600 focus:outline-none focus:ring-4 focus:ring-blue-600/5"
                                />
                            </div>
                        </div>

                        {error && (
                            <div className="flex items-center gap-3 p-4 rounded-2xl bg-red-50 border border-red-100 text-red-600 animate-in shake duration-300">
                                <AlertCircle size={20} />
                                <p className="text-xs font-bold uppercase tracking-widest">{error}</p>
                            </div>
                        )}

                        <button
                            type="submit"
                            disabled={isLoading}
                            className="group relative w-full h-16 flex items-center justify-center overflow-hidden rounded-3xl bg-blue-600 font-black text-white shadow-2xl shadow-blue-600/20 transition-all hover:bg-blue-700 hover:-translate-y-1 active:scale-95 disabled:opacity-50"
                        >
                            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000" />
                            {isLoading ? (
                                <Loader2 className="animate-spin" size={24} />
                            ) : (
                                <div className="flex items-center gap-3">
                                    <span className="uppercase tracking-[0.2em] text-sm">Login</span>
                                    <ArrowRight size={20} className="group-hover:translate-x-2 transition-transform" />
                                </div>
                            )}
                        </button>
                    </form>

                    <div className="mt-8 text-center">
                        <p className="text-[10px] font-black text-zinc-400 uppercase tracking-widest leading-loose">
                         Demo Login: naveenkumar@gmail.com / password123
                        </p>
                    </div>
                </div>

                <div className="text-center opacity-40">
                    <p className="text-[10px] font-black text-zinc-400 uppercase tracking-[0.4em]">CRM CORE ORCHESTRATOR</p>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { X, Save, Loader2, Sparkles, Phone, Mail, Users, FileText, Target, User as UserIcon } from "lucide-react";
import { Activity } from "@/lib/services/activity-service";
import { Lead } from "@/lib/services/lead-service";
import { User } from "@/lib/services/user-service";

interface ActivityDialogProps {
    isOpen: boolean;
    onClose: () => void;
    title: string;
    leads: Lead[];
    users: User[];
    initialData?: Activity;
    onSubmit: (data: Omit<Activity, "id" | "created_at" | "lead" | "user">) => void;
    isLoading?: boolean;
}

const activityTypes = [
    { label: "Call", value: "call", icon: Phone },
    { label: "Email", value: "email", icon: Mail },
    { label: "Meeting", value: "meeting", icon: Users },
    { label: "Note", value: "note", icon: FileText },
];

export function ActivityDialog({
    isOpen,
    onClose,
    title,
    leads,
    users,
    initialData,
    onSubmit,
    isLoading,
}: ActivityDialogProps) {
    const [formData, setFormData] = useState({
        type: "note",
        note: "",
        leadId: "",
        userId: "",
    });

    useEffect(() => {
        if (initialData) {
            setFormData({
                type: initialData.type || "note",
                note: initialData.note || "",
                leadId: initialData.leadId || "",
                userId: initialData.userId || "",
            });
        } else {
            setFormData({
                type: "note",
                note: "",
                leadId: "",
                userId: "",
            });
        }
    }, [initialData, isOpen]);

    if (!isOpen) return null;

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSubmit(formData);
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm animate-in fade-in duration-500">
            <div className="w-full max-w-xl rounded-[40px] bg-white p-10 shadow-2xl shadow-blue-900/10 border border-zinc-100 animate-in zoom-in-95 duration-500 max-h-[90vh] overflow-y-auto">
                <div className="flex items-center justify-between mb-8">
                    <div className="space-y-1">
                        <div className="flex items-center gap-3">
                            <Sparkles size={24} className="text-blue-500 animate-pulse" />
                            <h2 className="text-xl font-black tracking-tighter text-zinc-900">
                                {title}
                            </h2>
                        </div>
                        <p className="text-[10px] font-black tracking-[0.3em] text-zinc-400">Activity Logger</p>
                    </div>
                    <button
                        onClick={onClose}
                        className="rounded-2xl p-4 text-zinc-400 hover:bg-zinc-50 hover:text-zinc-900 transition-all border border-transparent hover:border-zinc-100"
                    >
                        <X size={24} />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="space-y-4">
                        <div className="space-y-2">
                            <label className="text-xs font-black tracking-widest text-zinc-500 ml-1">Activity Type</label>
                            <div className="grid grid-cols-4 gap-3">
                                {activityTypes.map((type) => {
                                    const Icon = type.icon;
                                    const isSelected = formData.type === type.value;
                                    return (
                                        <button
                                            key={type.value}
                                            type="button"
                                            onClick={() => setFormData({ ...formData, type: type.value })}
                                            className={`flex flex-col items-center justify-center gap-2 p-5 rounded-[24px] border transition-all ${
                                                isSelected
                                                    ? "bg-blue-600 border-blue-600 text-white shadow-xl shadow-blue-600/30 scale-105"
                                                    : "bg-white border-zinc-100 text-zinc-400 hover:bg-zinc-50"
                                            }`}
                                        >
                                            <Icon size={20} />
                                            <span className="text-[10px] font-black tracking-widest">{type.label}</span>
                                        </button>
                                    );
                                })}
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-black tracking-widest text-zinc-500 ml-1 flex items-center gap-2">
                                <FileText size={14} /> Notes / Details
                            </label>
                             <textarea
                                rows={4}
                                placeholder="Describe the operational specifics..."
                                value={formData.note}
                                onChange={(e) => setFormData({ ...formData, note: e.target.value })}
                                className="w-full rounded-[24px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-blue-600 focus:outline-none focus:ring-4 focus:ring-blue-600/5 placeholder:text-zinc-300 resize-none"
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-xs font-black tracking-widest text-zinc-500 ml-1 flex items-center gap-2">
                                    <Target size={14} /> Related Lead
                                </label>
                                 <select
                                    required
                                    value={formData.leadId}
                                    onChange={(e) => setFormData({ ...formData, leadId: e.target.value })}
                                    className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-blue-600 focus:outline-none focus:ring-4 focus:ring-blue-600/5 placeholder:text-zinc-300 appearance-none"
                                >
                                    <option value="">Select Lead...</option>
                                    {leads.map((lead) => (
                                        <option key={lead.id} value={lead.id}>
                                            {lead.name}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs font-black tracking-widest text-zinc-500 ml-1 flex items-center gap-2">
                                    <UserIcon size={14} /> Logged By
                                </label>
                                 <select
                                    value={formData.userId}
                                    onChange={(e) => setFormData({ ...formData, userId: e.target.value })}
                                    className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-zinc-900 focus:outline-none focus:ring-4 focus:ring-zinc-900/5 appearance-none"
                                >
                                    <option value="">Unknown</option>
                                    {users.map((user) => (
                                        <option key={user.id} value={user.id}>
                                            {user.name}
                                        </option>
                                    ))}
                                </select>
                            </div>
                        </div>
                    </div>

                    <div className="flex items-center gap-6 pt-10">
                        <button
                            type="button"
                            onClick={onClose}
                            className="h-16 flex-1 rounded-[24px] text-xs font-black tracking-widest text-zinc-400 hover:bg-zinc-50 hover:text-zinc-900 transition-all"
                        >
                            Discard
                        </button>
                        <button
                            type="submit"
                            disabled={isLoading}
                            className="h-16 flex-[2] flex items-center justify-center gap-4 rounded-[24px] bg-blue-600 text-xs font-black tracking-widest text-white shadow-2xl shadow-blue-600/30 hover:-translate-y-1 transition-all disabled:opacity-50 hover:bg-blue-700 active:scale-95"
                        >
                            {isLoading ? (
                                <Loader2 className="animate-spin" size={20} />
                            ) : (
                                <>
                                    <Save size={18} />
                                    Save
                                </>
                            )}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

"use client";

import { Activity } from "@/lib/services/activity-service";
import { 
    Phone, 
    Mail, 
    Users, 
    FileText, 
    Trash2, 
    User,
    Target,
    Clock
} from "lucide-react";

interface ActivityTimelineProps {
    activities: Activity[];
    onDelete: (id: string) => void;
}

const typeConfig: Record<string, { icon: any, color: string, label: string }> = {
    call: { icon: Phone, color: "bg-blue-500", label: "Phone Call" },
    email: { icon: Mail, color: "bg-emerald-500", label: "Email Sent" },
    meeting: { icon: Users, color: "bg-purple-500", label: "Meeting" },
    note: { icon: FileText, color: "bg-zinc-500", label: "Internal Note" },
};

export function ActivityTimeline({ activities, onDelete }: ActivityTimelineProps) {
    const formatDate = (dateString?: string) => {
        if (!dateString) return "";
        const date = new Date(dateString);
        return new Intl.DateTimeFormat('en-US', {
            month: 'short',
            day: 'numeric',
            hour: '2-digit',
            minute: '2-digit'
        }).format(date);
    };

    return (
        <div className="space-y-8 relative before:absolute before:inset-0 before:ml-5 before:-translate-x-px md:before:mx-auto md:before:translate-x-0 before:h-full before:w-px before:bg-gradient-to-b before:from-transparent before:via-zinc-200 before:to-transparent">
            {activities.map((activity, index) => {
                const config = typeConfig[activity.type] || typeConfig.note;
                const Icon = config.icon;

                return (
                    <div key={activity.id} className="relative flex items-center justify-between md:justify-normal md:odd:flex-row-reverse group animate-in slide-in-from-bottom-4 duration-500" style={{ animationDelay: `${index * 100}ms` }}>
                        {/* Dot */}
                        <div className="flex items-center justify-center w-12 h-12 rounded-[18px] border-4 border-white bg-zinc-50 text-zinc-400 shadow-xl md:order-1 md:group-odd:-translate-x-1/2 md:group-even:translate-x-1/2 z-10 transition-all group-hover:bg-blue-600 group-hover:text-white group-hover:rotate-6">
                            <Icon size={18} className="transition-transform" />
                        </div>

                        {/* Card */}
                        <div className="w-[calc(100%-4rem)] md:w-[calc(50%-2.5rem)] p-8 rounded-[40px] bg-white border border-zinc-100 shadow-2xl shadow-zinc-200/40 transition-all hover:-translate-y-2">
                            <div className="flex items-center justify-between mb-6">
                                <div className="flex items-center gap-4">
                                    <span className={`px-4 py-1.5 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] text-white shadow-lg ${config.color} shadow-${config.color.split('-')[1]}-200/40`}>
                                        {config.label}
                                    </span>
                                    <div className="flex items-center gap-2 text-zinc-300">
                                        <Clock size={12} className="opacity-40" />
                                        <time className="text-[10px] font-black uppercase tracking-widest">
                                            {formatDate(activity.created_at)}
                                        </time>
                                    </div>
                                </div>
                                <button
                                    onClick={() => activity.id && confirm("Erase this activity record?") && onDelete(activity.id)}
                                    className="p-3 rounded-2xl text-zinc-300 hover:text-white hover:bg-red-500 transition-all opacity-0 group-hover:opacity-100"
                                >
                                    <Trash2 size={16} />
                                </button>
                            </div>

                            <div className="space-y-6">
                                {activity.note && (
                                    <p className="text-zinc-900 font-black text-xl tracking-tighter leading-tight italic">
                                        "{activity.note}"
                                    </p>
                                )}

                                <div className="flex flex-wrap gap-6 pt-6 border-t border-zinc-50">
                                    {activity.lead && (
                                        <div className="flex items-center gap-3">
                                            <div className="p-2 rounded-xl bg-zinc-50 border border-zinc-100 group-hover:bg-blue-600 group-hover:text-white transition-all">
                                                <Target size={14} className="opacity-40" />
                                            </div>
                                            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-400">
                                                {activity.lead.name}
                                            </span>
                                        </div>
                                    )}
                                    {activity.user && (
                                        <div className="flex items-center gap-3">
                                            <div className="p-2 rounded-xl bg-zinc-50 border border-zinc-100 group-hover:bg-zinc-900 group-hover:text-white transition-all">
                                                <User size={14} className="opacity-40" />
                                            </div>
                                            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-400">
                                                {activity.user.name}
                                            </span>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                );
            })}

            {activities.length === 0 && (
                <div className="flex flex-col items-center justify-center py-32 text-center">
                    <div className="w-24 h-24 rounded-[32px] bg-zinc-50 border border-zinc-100 flex items-center justify-center mb-8">
                        <Clock size={40} className="text-zinc-200" />
                    </div>
                    <h3 className="text-2xl font-black tracking-tighter text-zinc-900 uppercase">Silence in the Ranks</h3>
                    <p className="text-zinc-400 font-bold text-[10px] tracking-[0.3em] uppercase opacity-60 mt-2">No activity has been orchestrated yet.</p>
                </div>
            )}
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { X, Save, Trash2, Loader2, Sparkles } from "lucide-react";
import { Deal } from "@/lib/services/deal-service";
import { Lead } from "@/lib/services/lead-service";
 
interface DealDialogProps {
    isOpen: boolean;
    onClose: () => void;
    title: string;
    leads: Lead[];
    initialData?: Deal;
    onSubmit: (data: Omit<Deal, "id" | "created_at" | "updated_at" | "lead">) => void;
    isLoading?: boolean;
}

export function DealDialog({
    isOpen,
    onClose,
    title,
    leads,
    initialData,
    onSubmit,
    isLoading,
}: DealDialogProps) {
    const [formData, setFormData] = useState({
        title: "",
        amount: 0,
        stage: "new",
        leadId: "",
    });

    useEffect(() => {
        if (initialData) {
            setFormData({
                title: initialData.title || "",
                amount: initialData.amount || 0,
                stage: initialData.stage || "new",
                leadId: initialData.leadId || "",
            });
        } else {
            setFormData({
                title: "",
                amount: 0,
                stage: "new",
                leadId: "",
            });
        }
    }, [initialData, isOpen]);

    if (!isOpen) return null;

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSubmit(formData);
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm animate-in fade-in duration-500">
            <div className="w-full max-w-xl rounded-[48px] bg-white p-12 shadow-2xl shadow-blue-900/10 border border-zinc-100 animate-in zoom-in-95 duration-500">
                <div className="flex items-center justify-between mb-10">
                    <div className="space-y-1">
                        <div className="flex items-center gap-3">
                            <Sparkles size={24} className="text-blue-500 animate-pulse" />
                            <h2 className="text-xl font-black tracking-tighter text-zinc-900">
                                {title}
                            </h2>
                        </div>
                        <p className="text-[10px] text-zinc-500 font-bold tracking-widest opacity-60">Track and manage your sales pipeline</p>
                    </div>
                    <button
                        onClick={onClose}
                        className="rounded-2xl p-4 text-zinc-400 hover:bg-zinc-50 hover:text-zinc-900 transition-all border border-transparent hover:border-zinc-100"
                    >
                        <X size={24} />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="space-y-8">
                    <div className="space-y-6">
                        <div className="space-y-2">
                            <label className="text-xs font-black  tracking-widest text-zinc-500 ml-1">Deal Title</label>
                            <input
                                required
                                type="text"
                                placeholder="e.g. Enterprise Global Expansion"
                                value={formData.title}
                                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                                className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-blue-600 focus:outline-none focus:ring-4 focus:ring-blue-600/5 placeholder:text-zinc-300"
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-6">
                            <div className="space-y-2">
                                <label className="text-xs font-black tracking-widest text-zinc-500 ml-1">Value ($)</label>
                                <input
                                    required
                                    type="number"
                                    placeholder="50000"
                                    value={formData.amount}
                                    onChange={(e) => setFormData({ ...formData, amount: parseFloat(e.target.value) })}
                                    className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-zinc-900 focus:outline-none focus:ring-4 focus:ring-zinc-900/5 appearance-none"
                                />
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs font-black tracking-widest text-zinc-500 ml-1">Stage</label>
                                <select
                                    value={formData.stage}
                                    onChange={(e) => setFormData({ ...formData, stage: e.target.value })}
                                    className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-zinc-900 focus:outline-none focus:ring-4 focus:ring-zinc-900/5 appearance-none"
                                >
                                    <option value="new">Target Acquisition</option>
                                    <option value="negotiation">Active Negotiation</option>
                                    <option value="closed_won">Operational Success</option>
                                    <option value="closed_lost">Tactical Withdrawal</option>
                                </select>
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-black tracking-widest text-zinc-500 ml-1">Associated Lead</label>
                            <select
                                required
                                value={formData.leadId}
                                onChange={(e) => setFormData({ ...formData, leadId: e.target.value })}
